/**
 * User notification preferences model.
 *
 * Controls how and when users receive notifications across multiple channels.
 *
 * Decision change (Agent 9): The original email-only assumption from Agent 3
 * is no longer valid. SMS support was added in Agent 8, and webhook support
 * exists via Agent 6. This model now supports per-channel preference sections
 * for email, SMS, and webhook. Backward compatibility is preserved: existing
 * email-only preferences continue to work, and SMS/webhook default to disabled
 * (opt-in model for non-email channels).
 */

import type { NotificationType } from './notification.js';

/** How often batched/digest notifications are delivered. */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly';

/**
 * Email-specific notification settings.
 */
export interface EmailPreferences {
  /** Master toggle — when false, no emails are sent regardless of other settings. */
  enabled: boolean;
  /** Delivery frequency for non-urgent notifications. */
  frequency: EmailFrequency;
  /** Notification categories the user is subscribed to. */
  subscribedCategories: NotificationType[];
}

/**
 * SMS-specific notification settings.
 * SMS uses an opt-in model — disabled by default, requires a phone number.
 */
export interface SmsPreferences {
  /** Master toggle — when false, no SMS messages are sent. */
  enabled: boolean;
  /** The user's phone number for receiving SMS (E.164 format recommended). */
  phoneNumber: string;
  /** Notification categories the user is subscribed to via SMS. */
  subscribedCategories: NotificationType[];
}

/**
 * Webhook-specific notification settings.
 * Webhooks use an opt-in model — disabled by default, requires a URL.
 */
export interface WebhookPreferences {
  /** Master toggle — when false, no webhooks are sent. */
  enabled: boolean;
  /** The webhook endpoint URL. */
  url: string;
  /** Notification categories the user is subscribed to via webhook. */
  subscribedCategories: NotificationType[];
}

/**
 * Full user notification preferences record.
 * Each channel has its own settings section.
 */
export interface UserPreferences {
  /** Unique ID for this preferences record. */
  id: string;
  /** The user this preferences record belongs to. */
  userId: string;
  /** Email notification settings. */
  email: EmailPreferences;
  /** SMS notification settings (opt-in, disabled by default). */
  sms: SmsPreferences;
  /** Webhook notification settings (opt-in, disabled by default). */
  webhook: WebhookPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for updating email preferences (all fields optional).
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating SMS preferences (all fields optional).
 */
export interface UpdateSmsPreferencesInput {
  enabled?: boolean;
  phoneNumber?: string;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating webhook preferences (all fields optional).
 */
export interface UpdateWebhookPreferencesInput {
  enabled?: boolean;
  url?: string;
  subscribedCategories?: NotificationType[];
}

/**
 * Default email preferences applied to new users.
 * Email uses opt-out: enabled by default, all categories subscribed.
 */
export const defaultEmailPreferences: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [
    'order_confirmation',
    'order_status_update',
    'user_welcome',
    'user_updated',
  ],
};

/**
 * Default SMS preferences applied to new users.
 * SMS uses opt-in: disabled by default, no phone number.
 */
export const defaultSmsPreferences: SmsPreferences = {
  enabled: false,
  phoneNumber: '',
  subscribedCategories: [],
};

/**
 * Default webhook preferences applied to new users.
 * Webhook uses opt-in: disabled by default, no URL.
 */
export const defaultWebhookPreferences: WebhookPreferences = {
  enabled: false,
  url: '',
  subscribedCategories: [],
};

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Stores per-channel preferences as flattened fields with JSON-stringified categories.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type {
  UserPreferences,
  EmailPreferences,
  SmsPreferences,
  WebhookPreferences,
} from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as EmailPreferences['frequency'],
        subscribedCategories: JSON.parse(
          record['emailSubscribedCategories'] as string,
        ) as NotificationType[],
      },
      sms: {
        enabled: (record['smsEnabled'] as boolean) ?? false,
        phoneNumber: (record['smsPhoneNumber'] as string) ?? '',
        subscribedCategories: record['smsSubscribedCategories']
          ? (JSON.parse(record['smsSubscribedCategories'] as string) as NotificationType[])
          : [],
      },
      webhook: {
        enabled: (record['webhookEnabled'] as boolean) ?? false,
        url: (record['webhookUrl'] as string) ?? '',
        subscribedCategories: record['webhookSubscribedCategories']
          ? (JSON.parse(record['webhookSubscribedCategories'] as string) as NotificationType[])
          : [],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailSubscribedCategories: JSON.stringify(entity.email.subscribedCategories),
      smsEnabled: entity.sms.enabled,
      smsPhoneNumber: entity.sms.phoneNumber,
      smsSubscribedCategories: JSON.stringify(entity.sms.subscribedCategories),
      webhookEnabled: entity.webhook.enabled,
      webhookUrl: entity.webhook.url,
      webhookSubscribedCategories: JSON.stringify(entity.webhook.subscribedCategories),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences for a specific user.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Architecture:
 * - Uses EventBus to auto-create default preferences when a user is created.
 * - Provides CRUD for user notification preferences across all channels.
 * - The NotificationService consults this service before sending.
 *
 * Decision change (Agent 9): Now supports per-channel preferences for email,
 * SMS, and webhook. Email uses opt-out (enabled by default); SMS and webhook
 * use opt-in (disabled by default). The shouldSendEmail() method is preserved
 * for backward compatibility alongside the new shouldSendSms(), shouldSendWebhook(),
 * and generic shouldSendToChannel() methods.
 */

import type { EventBus } from '../events/event-bus.js';
import type { UserCreatedEvent } from '../events/event-types.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  UpdateEmailPreferencesInput,
  UpdateSmsPreferencesInput,
  UpdateWebhookPreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import {
  defaultEmailPreferences,
  defaultSmsPreferences,
  defaultWebhookPreferences,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset ID counter (for testing). */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(
    private repository: PreferencesRepository,
    private eventBus: EventBus,
  ) {
    this.registerEventHandlers();
  }

  /**
   * Listen for user:created events to auto-provision default preferences.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<UserCreatedEvent>('user:created', async (event) => {
      await this.createDefaultPreferences(event.user.id);
    });
  }

  /**
   * Create default preferences for a user.
   * No-op if preferences already exist.
   */
  async createDefaultPreferences(userId: string): Promise<UserPreferences> {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      this.logger.info(`Preferences already exist for user ${userId}`);
      return existing;
    }

    const now = new Date();
    const prefs: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: { ...defaultEmailPreferences, subscribedCategories: [...defaultEmailPreferences.subscribedCategories] },
      sms: { ...defaultSmsPreferences, subscribedCategories: [...defaultSmsPreferences.subscribedCategories] },
      webhook: { ...defaultWebhookPreferences, subscribedCategories: [...defaultWebhookPreferences.subscribedCategories] },
      createdAt: now,
      updatedAt: now,
    };

    this.repository.save(prefs);
    this.logger.info(`Created default preferences for user ${userId}`);
    return prefs;
  }

  /**
   * Get preferences for a user. Returns undefined if none exist.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.repository.findByUserId(userId);
  }

  /**
   * Update email preferences for a user.
   * Only the provided fields are changed; unset fields keep their current values.
   */
  updateEmailPreferences(
    userId: string,
    input: UpdateEmailPreferencesInput,
  ): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      throw new Error(`Preferences not found for user: ${userId}`);
    }

    const updatedEmail = { ...existing.email };
    if (input.enabled !== undefined) {
      updatedEmail.enabled = input.enabled;
    }
    if (input.frequency !== undefined) {
      updatedEmail.frequency = input.frequency;
    }
    if (input.subscribedCategories !== undefined) {
      updatedEmail.subscribedCategories = input.subscribedCategories;
    }

    return this.repository.update(existing.id, {
      email: updatedEmail,
      updatedAt: new Date(),
    });
  }

  /**
   * Update SMS preferences for a user.
   * Only the provided fields are changed; unset fields keep their current values.
   */
  updateSmsPreferences(
    userId: string,
    input: UpdateSmsPreferencesInput,
  ): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      throw new Error(`Preferences not found for user: ${userId}`);
    }

    const updatedSms = { ...existing.sms };
    if (input.enabled !== undefined) {
      updatedSms.enabled = input.enabled;
    }
    if (input.phoneNumber !== undefined) {
      updatedSms.phoneNumber = input.phoneNumber;
    }
    if (input.subscribedCategories !== undefined) {
      updatedSms.subscribedCategories = input.subscribedCategories;
    }

    return this.repository.update(existing.id, {
      sms: updatedSms,
      updatedAt: new Date(),
    });
  }

  /**
   * Update webhook preferences for a user.
   * Only the provided fields are changed; unset fields keep their current values.
   */
  updateWebhookPreferences(
    userId: string,
    input: UpdateWebhookPreferencesInput,
  ): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      throw new Error(`Preferences not found for user: ${userId}`);
    }

    const updatedWebhook = { ...existing.webhook };
    if (input.enabled !== undefined) {
      updatedWebhook.enabled = input.enabled;
    }
    if (input.url !== undefined) {
      updatedWebhook.url = input.url;
    }
    if (input.subscribedCategories !== undefined) {
      updatedWebhook.subscribedCategories = input.subscribedCategories;
    }

    return this.repository.update(existing.id, {
      webhook: updatedWebhook,
      updatedAt: new Date(),
    });
  }

  /**
   * Check whether a notification should be sent to a user via email.
   * Returns true if: preferences exist, email is enabled, and the
   * notification type is in the user's subscribed categories.
   *
   * If no preferences record exists (e.g. legacy user), defaults to
   * allowing the notification (opt-out model).
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);
    if (!prefs) {
      return true; // opt-out: legacy users get emails
    }
    if (!prefs.email.enabled) {
      return false;
    }
    return prefs.email.subscribedCategories.includes(notificationType);
  }

  /**
   * Check whether a notification should be sent to a user via SMS.
   * SMS uses opt-in: returns false if no preferences exist or SMS is not enabled.
   */
  shouldSendSms(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);
    if (!prefs) {
      return false; // opt-in: no prefs means no SMS
    }
    if (!prefs.sms.enabled) {
      return false;
    }
    if (!prefs.sms.phoneNumber) {
      return false;
    }
    return prefs.sms.subscribedCategories.includes(notificationType);
  }

  /**
   * Check whether a notification should be sent to a user via webhook.
   * Webhook uses opt-in: returns false if no preferences exist or webhook is not enabled.
   */
  shouldSendWebhook(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);
    if (!prefs) {
      return false; // opt-in: no prefs means no webhook
    }
    if (!prefs.webhook.enabled) {
      return false;
    }
    if (!prefs.webhook.url) {
      return false;
    }
    return prefs.webhook.subscribedCategories.includes(notificationType);
  }

  /**
   * Generic channel check — dispatches to the appropriate per-channel method.
   * For unknown channels, returns false.
   */
  shouldSendToChannel(
    userId: string,
    channel: NotificationChannel,
    notificationType: NotificationType,
  ): boolean {
    switch (channel) {
      case 'email':
        return this.shouldSendEmail(userId, notificationType);
      case 'sms':
        return this.shouldSendSms(userId, notificationType);
      case 'webhook':
        return this.shouldSendWebhook(userId, notificationType);
      default:
        return false;
    }
  }

  /**
   * Get the recipient address for a given channel.
   * Returns the phone number for SMS, URL for webhook, or undefined if not configured.
   */
  getChannelRecipient(userId: string, channel: NotificationChannel): string | undefined {
    const prefs = this.repository.findByUserId(userId);
    if (!prefs) {
      return undefined;
    }
    switch (channel) {
      case 'sms':
        return prefs.sms.phoneNumber || undefined;
      case 'webhook':
        return prefs.webhook.url || undefined;
      default:
        return undefined;
    }
  }
}

/**
 * Notification service — dispatches notifications in response to domain events.
 *
 * Architecture:
 * - PATTERN: Event-driven via EventBus (exclusively). No direct service calls.
 * - FLOW: Domain event → NotificationService handler → NotificationAdapter.send()
 * - ADAPTERS: Registered per channel. All must implement NotificationAdapter.
 * - MULTI-CHANNEL: Event handlers now route to all enabled channels per user
 *   preferences. Email remains the default channel; SMS and webhook are sent
 *   when the user has opted in via preferences.
 *
 * Constraints:
 * - All notifications MUST originate from EventBus event handlers.
 * - All delivery channels MUST be registered as adapters via registerAdapter().
 * - Adapters are dispatched based on NotificationPayload.channel.
 * - The service emits 'notification:sent' and 'notification:failed' events
 *   for observability, but these MUST NOT trigger further notifications
 *   (no recursive loops).
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type {
  Notification,
  NotificationChannel,
  NotificationType,
  CreateNotificationInput,
} from '../models/notification.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type { PreferencesService } from './preferences.service.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset ID counter (for testing). */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

/** Channels that event handlers will attempt to route to. */
const ROUTABLE_CHANNELS: NotificationChannel[] = ['email', 'sms', 'webhook'];

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private preferencesService: PreferencesService | null = null;

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Set the preferences service for checking user notification preferences.
   * Optional — when not set, all notifications are sent via email only (backwards compatible).
   */
  setPreferencesService(preferencesService: PreferencesService): void {
    this.preferencesService = preferencesService;
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is supported; registering a second
   * adapter for the same channel replaces the first.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Get the adapter registered for a given channel, if any.
   */
  getAdapter(channel: NotificationChannel): NotificationAdapter | undefined {
    return this.adapters.get(channel);
  }

  /**
   * Subscribe to domain events on the EventBus.
   * All notification triggers are wired here — this is the single
   * entry point for all notification-producing events.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Determine which channels should receive a notification for a given user
   * and notification type. When no preferences service is set, defaults to
   * email-only for backward compatibility.
   */
  private getEnabledChannels(
    userId: string,
    notificationType: NotificationType,
  ): Array<{ channel: NotificationChannel; recipient: string | null }> {
    if (!this.preferencesService) {
      // No preferences service — email-only backward compatibility
      return [{ channel: 'email', recipient: null }];
    }

    const channels: Array<{ channel: NotificationChannel; recipient: string | null }> = [];

    for (const channel of ROUTABLE_CHANNELS) {
      if (this.preferencesService.shouldSendToChannel(userId, channel, notificationType)) {
        const recipient = this.preferencesService.getChannelRecipient(userId, channel);
        channels.push({ channel, recipient: recipient ?? null });
      }
    }

    return channels;
  }

  /**
   * Handle order created event — send confirmation notification to all enabled channels.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const channels = this.getEnabledChannels(event.user.id, 'order_confirmation');

    if (channels.length === 0) {
      this.logger.info(`Skipping order confirmation for order ${event.order.id} — user ${event.user.id} opted out of all channels`);
      return;
    }

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    for (const { channel, recipient } of channels) {
      // For email, use the user's email address from the event.
      // For other channels, use the recipient from preferences.
      const resolvedRecipient = channel === 'email' ? event.user.email : (recipient ?? event.user.id);

      this.logger.info(`Sending order confirmation for order ${event.order.id} via ${channel}`);

      await this.createAndSend({
        type: 'order_confirmation',
        channel,
        recipient: resolvedRecipient,
        subject: `Order Confirmation: ${event.order.id}`,
        body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
        priority: 'normal',
        metadata: {
          orderId: event.order.id,
          userId: event.user.id,
        },
      });
    }
  }

  /**
   * Handle order status change — send update notification to all enabled channels.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    const channels = this.getEnabledChannels(event.order.userId, 'order_status_update');

    if (channels.length === 0) {
      this.logger.info(
        `Skipping status update for order ${event.order.id} — user ${event.order.userId} opted out of all channels`,
      );
      return;
    }

    for (const { channel, recipient } of channels) {
      const resolvedRecipient = channel === 'email' ? event.order.userId : (recipient ?? event.order.userId);

      this.logger.info(
        `Sending status update for order ${event.order.id} via ${channel}: ${event.previousStatus} -> ${event.newStatus}`,
      );

      await this.createAndSend({
        type: 'order_status_update',
        channel,
        recipient: resolvedRecipient,
        subject: `Order Update: ${event.order.id}`,
        body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
        priority: 'normal',
        metadata: {
          orderId: event.order.id,
          previousStatus: event.previousStatus,
          newStatus: event.newStatus,
        },
      });
    }
  }

  /**
   * Create a notification record and attempt delivery via the appropriate adapter.
   * If no adapter is registered for the channel, the notification is stored
   * with 'pending' status (for later delivery or manual inspection).
   */
  async createAndSend(input: CreateNotificationInput): Promise<Notification> {
    const notification: Notification = {
      id: generateNotificationId(),
      type: input.type,
      channel: input.channel,
      recipient: input.recipient,
      subject: input.subject,
      body: input.body,
      priority: input.priority ?? 'normal',
      metadata: input.metadata ?? {},
      createdAt: new Date(),
      status: 'pending',
      sentAt: null,
      error: null,
    };

    this.notifications.push(notification);

    const adapter = this.adapters.get(input.channel);
    if (!adapter) {
      this.logger.warn(
        `No adapter registered for channel "${input.channel}". Notification ${notification.id} stored as pending.`,
      );
      return notification;
    }

    try {
      const result = await adapter.send(notification);
      if (result.success) {
        notification.status = 'sent';
        notification.sentAt = new Date();
        this.logger.info(`Notification ${notification.id} sent successfully`);

        await this.eventBus.emit({
          type: 'notification:sent',
          notification,
          timestamp: new Date(),
        });
      } else {
        notification.status = 'failed';
        notification.error = result.error ?? 'Unknown delivery error';
        this.logger.error(`Notification ${notification.id} failed: ${notification.error}`);

        await this.eventBus.emit({
          type: 'notification:failed',
          notification,
          error: notification.error,
          timestamp: new Date(),
        });
      }
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown error';
      notification.status = 'failed';
      notification.error = errorMessage;
      this.logger.error(`Notification ${notification.id} threw: ${errorMessage}`);

      await this.eventBus.emit({
        type: 'notification:failed',
        notification,
        error: errorMessage,
        timestamp: new Date(),
      });
    }

    return notification;
  }

  /**
   * Get all notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Get notifications filtered by status.
   */
  getNotificationsByStatus(status: Notification['status']): Notification[] {
    return this.notifications.filter((n) => n.status === status);
  }

  /**
   * Clear all notifications (for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

