import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { defaultEmailPreferences } from '../../src/models/user-preferences.js';
import type { UserCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let eventBus: EventBus;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository, eventBus);
    resetPreferencesIdCounter();
  });

  describe('createDefaultPreferences', () => {
    it('should create default preferences for a user', async () => {
      const prefs = await service.createDefaultPreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.id).toBe('pref-0001');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(
        defaultEmailPreferences.subscribedCategories,
      );
    });

    it('should create SMS defaults as disabled (opt-in)', async () => {
      const prefs = await service.createDefaultPreferences('user-1');

      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.sms.phoneNumber).toBe('');
      expect(prefs.sms.subscribedCategories).toEqual([]);
    });

    it('should create webhook defaults as disabled (opt-in)', async () => {
      const prefs = await service.createDefaultPreferences('user-1');

      expect(prefs.webhook.enabled).toBe(false);
      expect(prefs.webhook.url).toBe('');
      expect(prefs.webhook.subscribedCategories).toEqual([]);
    });

    it('should return existing preferences without creating duplicates', async () => {
      const first = await service.createDefaultPreferences('user-1');
      const second = await service.createDefaultPreferences('user-1');

      expect(first.id).toBe(second.id);
      expect(repository.count()).toBe(1);
    });

    it('should auto-create preferences on user:created event', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

