  describe('getPreferences', () => {
    it('should return undefined for unknown user', () => {
      expect(service.getPreferences('nonexistent')).toBeUndefined();
    });

    it('should return preferences for a known user', async () => {
      await service.createDefaultPreferences('user-1');
      const prefs = service.getPreferences('user-1');

      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });
  });

  describe('updateEmailPreferences', () => {
    it('should disable email notifications', async () => {
      await service.createDefaultPreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', { enabled: false });

      expect(updated.email.enabled).toBe(false);
      // Other fields unchanged
      expect(updated.email.frequency).toBe('immediate');
      expect(updated.email.subscribedCategories).toEqual(
        defaultEmailPreferences.subscribedCategories,
      );
    });

    it('should change frequency', async () => {
      await service.createDefaultPreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', { frequency: 'daily' });

      expect(updated.email.frequency).toBe('daily');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update subscribed categories', async () => {
      await service.createDefaultPreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order_confirmation'],
      });

      expect(updated.email.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should update multiple fields at once', async () => {
      await service.createDefaultPreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        enabled: true,
        frequency: 'weekly',
        subscribedCategories: ['order_confirmation', 'order_status_update'],
      });

      expect(updated.email.enabled).toBe(true);
      expect(updated.email.frequency).toBe('weekly');
      expect(updated.email.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
      ]);
    });

    it('should throw for unknown user', () => {
      expect(() =>
        service.updateEmailPreferences('nonexistent', { enabled: false }),
      ).toThrow('Preferences not found for user: nonexistent');
    });

    it('should update the updatedAt timestamp', async () => {
      const prefs = await service.createDefaultPreferences('user-1');
      const originalUpdatedAt = prefs.updatedAt;

      // Small delay to ensure different timestamp
      await new Promise((r) => setTimeout(r, 5));

      const updated = service.updateEmailPreferences('user-1', { frequency: 'daily' });
      expect(updated.updatedAt.getTime()).toBeGreaterThan(originalUpdatedAt.getTime());
    });
