  describe('updateSmsPreferences', () => {
    it('should enable SMS with phone number and categories', async () => {
      await service.createDefaultPreferences('user-1');
      const updated = service.updateSmsPreferences('user-1', {
        enabled: true,
        phoneNumber: '+15551234567',
        subscribedCategories: ['order_confirmation', 'order_status_update'],
      });

      expect(updated.sms.enabled).toBe(true);
      expect(updated.sms.phoneNumber).toBe('+15551234567');
      expect(updated.sms.subscribedCategories).toEqual(['order_confirmation', 'order_status_update']);
    });

    it('should update only provided fields', async () => {
      await service.createDefaultPreferences('user-1');
      service.updateSmsPreferences('user-1', {
        enabled: true,
        phoneNumber: '+15551234567',
        subscribedCategories: ['order_confirmation'],
      });

      const updated = service.updateSmsPreferences('user-1', { enabled: false });
      expect(updated.sms.enabled).toBe(false);
      expect(updated.sms.phoneNumber).toBe('+15551234567');
      expect(updated.sms.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should throw for unknown user', () => {
      expect(() =>
        service.updateSmsPreferences('nonexistent', { enabled: true }),
      ).toThrow('Preferences not found for user: nonexistent');
    });
  });

  describe('updateWebhookPreferences', () => {
    it('should enable webhook with URL and categories', async () => {
      await service.createDefaultPreferences('user-1');
      const updated = service.updateWebhookPreferences('user-1', {
        enabled: true,
        url: 'https://example.com/webhook',
        subscribedCategories: ['order_confirmation'],
      });

      expect(updated.webhook.enabled).toBe(true);
      expect(updated.webhook.url).toBe('https://example.com/webhook');
      expect(updated.webhook.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should update only provided fields', async () => {
      await service.createDefaultPreferences('user-1');
      service.updateWebhookPreferences('user-1', {
        enabled: true,
        url: 'https://example.com/webhook',
        subscribedCategories: ['order_confirmation'],
      });

      const updated = service.updateWebhookPreferences('user-1', { url: 'https://new.example.com/webhook' });
      expect(updated.webhook.enabled).toBe(true);
      expect(updated.webhook.url).toBe('https://new.example.com/webhook');
      expect(updated.webhook.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should throw for unknown user', () => {
      expect(() =>
        service.updateWebhookPreferences('nonexistent', { enabled: true }),
      ).toThrow('Preferences not found for user: nonexistent');
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (opt-out model)', () => {
      expect(service.shouldSendEmail('unknown-user', 'order_confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', async () => {
      await service.createDefaultPreferences('user-1');
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is disabled', async () => {
      await service.createDefaultPreferences('user-1');
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when category is not subscribed', async () => {
      await service.createDefaultPreferences('user-1');
      service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendEmail('user-1', 'order_status_update')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false for unsubscribed category even when email is enabled', async () => {
      await service.createDefaultPreferences('user-1');
      service.updateEmailPreferences('user-1', {
        subscribedCategories: [],
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'user_welcome')).toBe(false);
    });
  });

  describe('shouldSendSms', () => {
    it('should return false when no preferences exist (opt-in model)', () => {
      expect(service.shouldSendSms('unknown-user', 'order_confirmation')).toBe(false);
    });

    it('should return false when SMS is disabled (default)', async () => {
      await service.createDefaultPreferences('user-1');
      expect(service.shouldSendSms('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when SMS is enabled but no phone number', async () => {
      await service.createDefaultPreferences('user-1');
      service.updateSmsPreferences('user-1', {
        enabled: true,
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendSms('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return true when SMS is enabled with phone and subscribed category', async () => {
      await service.createDefaultPreferences('user-1');
      service.updateSmsPreferences('user-1', {
        enabled: true,
        phoneNumber: '+15551234567',
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendSms('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false for unsubscribed category', async () => {
      await service.createDefaultPreferences('user-1');
      service.updateSmsPreferences('user-1', {
        enabled: true,
        phoneNumber: '+15551234567',
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendSms('user-1', 'order_status_update')).toBe(false);
    });
  });

  describe('shouldSendWebhook', () => {
    it('should return false when no preferences exist (opt-in model)', () => {
      expect(service.shouldSendWebhook('unknown-user', 'order_confirmation')).toBe(false);
    });

    it('should return false when webhook is disabled (default)', async () => {
      await service.createDefaultPreferences('user-1');
      expect(service.shouldSendWebhook('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when webhook is enabled but no URL', async () => {
      await service.createDefaultPreferences('user-1');
      service.updateWebhookPreferences('user-1', {
        enabled: true,
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendWebhook('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return true when webhook is enabled with URL and subscribed category', async () => {
      await service.createDefaultPreferences('user-1');
      service.updateWebhookPreferences('user-1', {
        enabled: true,
        url: 'https://example.com/webhook',
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendWebhook('user-1', 'order_confirmation')).toBe(true);
    });
  });

  describe('shouldSendToChannel', () => {
    it('should dispatch to email check', async () => {
      await service.createDefaultPreferences('user-1');
      expect(service.shouldSendToChannel('user-1', 'email', 'order_confirmation')).toBe(true);
    });

    it('should dispatch to SMS check', async () => {
      await service.createDefaultPreferences('user-1');
      expect(service.shouldSendToChannel('user-1', 'sms', 'order_confirmation')).toBe(false);
    });

    it('should dispatch to webhook check', async () => {
      await service.createDefaultPreferences('user-1');
      expect(service.shouldSendToChannel('user-1', 'webhook', 'order_confirmation')).toBe(false);
    });

    it('should return false for unknown channels', async () => {
      await service.createDefaultPreferences('user-1');
      expect(service.shouldSendToChannel('user-1', 'in-app', 'order_confirmation')).toBe(false);
    });
  });

  describe('getChannelRecipient', () => {
    it('should return undefined when no preferences exist', () => {
      expect(service.getChannelRecipient('unknown', 'sms')).toBeUndefined();
    });

    it('should return phone number for SMS', async () => {
      await service.createDefaultPreferences('user-1');
      service.updateSmsPreferences('user-1', { phoneNumber: '+15551234567' });

      expect(service.getChannelRecipient('user-1', 'sms')).toBe('+15551234567');
    });

    it('should return URL for webhook', async () => {
      await service.createDefaultPreferences('user-1');
      service.updateWebhookPreferences('user-1', { url: 'https://example.com/webhook' });

      expect(service.getChannelRecipient('user-1', 'webhook')).toBe('https://example.com/webhook');
    });

    it('should return undefined for email channel (email comes from event)', async () => {
      await service.createDefaultPreferences('user-1');
      expect(service.getChannelRecipient('user-1', 'email')).toBeUndefined();
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationService', () => {
  let eventBus: EventBus;
  let service: NotificationService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    service = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    service.registerAdapter(emailAdapter);
    resetNotificationIdCounter();
  });

  describe('order:created handler', () => {
    it('should send notification on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.recipient).toBe('alice@example.com');
      expect(notifications[0]?.subject).toContain('Order Confirmation');
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('$20.00');
      expect(notifications[0]?.status).toBe('sent');
      expect(notifications[0]?.type).toBe('order_confirmation');
      expect(notifications[0]?.channel).toBe('email');
    });

    it('should include all items in notification body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('Gadget x1');
    });
  });

  describe('order:status-changed handler', () => {
    it('should send notification on status change via EventBus', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.subject).toContain('Order Update');
      expect(notifications[0]?.body).toContain('pending');
      expect(notifications[0]?.body).toContain('confirmed');
      expect(notifications[0]?.type).toBe('order_status_update');
    });
  });

  describe('adapter management', () => {
    it('should store notification as pending when no adapter is registered', async () => {
      const serviceNoAdapter = new NotificationService(eventBus);
      resetNotificationIdCounter();

      const notification = await serviceNoAdapter.createAndSend({
        type: 'order_confirmation',
        channel: 'email',
        recipient: 'test@example.com',
        subject: 'Test',
        body: 'Test body',
      });

      expect(notification.status).toBe('pending');
      expect(notification.sentAt).toBeNull();
    });

    it('should deliver via registered adapter', async () => {
      const notification = await service.createAndSend({
        type: 'order_confirmation',
        channel: 'email',
        recipient: 'test@example.com',
        subject: 'Test',
        body: 'Test body',
      });

      expect(notification.status).toBe('sent');
      expect(notification.sentAt).not.toBeNull();
      const sent = emailAdapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('test@example.com');
    });

    it('should return registered adapter', () => {
      expect(service.getAdapter('email')).toBe(emailAdapter);
      expect(service.getAdapter('sms')).toBeUndefined();
    });
  });

  describe('notification management', () => {
    it('should count notifications', async () => {
      expect(service.getNotificationCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      expect(service.getNotificationCount()).toBe(1);
    });

    it('should filter by recipient', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(service.getNotificationsForRecipient('alice@example.com')).toHaveLength(1);
      expect(service.getNotificationsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear notifications', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      service.clearNotifications();
      expect(service.getNotificationCount()).toBe(0);
    });

    it('should generate sequential notification IDs', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      const notifications = service.getNotifications();
      expect(notifications[0]?.id).toBe('notif-0001');
      expect(notifications[1]?.id).toBe('notif-0002');
    });

    it('should filter by status', async () => {
      // With adapter → sent
      await service.createAndSend({
        type: 'order_confirmation',
        channel: 'email',
        recipient: 'test@example.com',
        subject: 'Test',
        body: 'Test body',
      });

      // Without adapter → pending
      const serviceNoAdapter = new NotificationService(new EventBus());
      await serviceNoAdapter.createAndSend({
        type: 'order_confirmation',
        channel: 'sms',
        recipient: '+1234567890',
        subject: 'Test',
        body: 'Test body',
      });

      expect(service.getNotificationsByStatus('sent')).toHaveLength(1);
      expect(serviceNoAdapter.getNotificationsByStatus('pending')).toHaveLength(1);
    });
  });

  describe('notification events', () => {
    it('should emit notification:sent event on successful delivery', async () => {
      await service.createAndSend({
        type: 'order_confirmation',
        channel: 'email',
        recipient: 'test@example.com',
        subject: 'Test',
        body: 'Test body',
      });

      const log = eventBus.getEventLog();
      const sentEvents = log.filter((e) => e.type === 'notification:sent');
      expect(sentEvents).toHaveLength(1);
    });
  });

  describe('multi-channel routing', () => {
    let db: Database;
    let preferencesRepo: PreferencesRepository;
    let preferencesService: PreferencesService;
    let smsAdapter: SmsAdapter;
    let webhookAdapter: WebhookAdapter;

    beforeEach(() => {
      db = new Database();
      preferencesRepo = new PreferencesRepository(db);
      preferencesService = new PreferencesService(preferencesRepo, eventBus);
      service.setPreferencesService(preferencesService);
      resetPreferencesIdCounter();

      smsAdapter = new SmsAdapter({ fromNumber: '+15559999999' });
      webhookAdapter = new WebhookAdapter({ url: 'https://example.com/webhook' });
      service.registerAdapter(smsAdapter);
      service.registerAdapter(webhookAdapter);
    });

    it('should send email only by default (SMS/webhook disabled)', async () => {
      await preferencesService.createDefaultPreferences('user-1');

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.channel).toBe('email');
    });

    it('should send to email and SMS when user opts into SMS', async () => {
      await preferencesService.createDefaultPreferences('user-1');
      preferencesService.updateSmsPreferences('user-1', {
        enabled: true,
        phoneNumber: '+15551234567',
        subscribedCategories: ['order_confirmation'],
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(2);

      const emailNotif = notifications.find((n) => n.channel === 'email');
      const smsNotif = notifications.find((n) => n.channel === 'sms');

      expect(emailNotif).toBeDefined();
      expect(emailNotif!.recipient).toBe('alice@example.com');
      expect(emailNotif!.status).toBe('sent');

      expect(smsNotif).toBeDefined();
      expect(smsNotif!.recipient).toBe('+15551234567');
      expect(smsNotif!.status).toBe('sent');
    });

    it('should send to all three channels when all enabled', async () => {
      await preferencesService.createDefaultPreferences('user-1');
