      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.channel).toBe('email');
    });

    it('should only send to channels where notification type is subscribed', async () => {
      await preferencesService.createDefaultPreferences('user-1');
      // SMS enabled but only for order_status_update, not order_confirmation
      preferencesService.updateSmsPreferences('user-1', {
